// Build one SaveTransferOrder payload per unique (customer, deliveryPlace)
const input = $('Sub-Workflow Input').first().json;
const config = input.config || {};
const lines = input.validatedLines || [];

const submittableLines = lines.filter(l => l.articleId && l.valid !== false);
const skippedLines = lines.filter(l => !l.articleId || l.valid === false);

// Group submittable lines by (customer, deliveryPlace)
const groups = {};
for (const line of submittableLines) {
  const custId = line.customer || '';
  const dpId = line.deliveryPlace || '';
  const key = custId + '|' + dpId;
  if (!groups[key]) {
    groups[key] = { customer: custId, deliveryPlace: dpId, customerName: line.customerName || '', lines: [] };
  }
  groups[key].lines.push(line);
}

const groupKeys = Object.keys(groups);
const accessToken = $('WF-00b: Get Token').first().json.accessToken;
const baseOrderNum = 'MP-' + (input.emailId || '').substring(0, 8) + '-' + Date.now();
const orderDate = (input.receivedAt || new Date().toISOString()).split('T')[0];

return groupKeys.map((key, idx) => {
  const g = groups[key];
  const orderNum = groupKeys.length > 1 ? baseOrderNum + '-' + (idx + 1) : baseOrderNum;
  return {
    json: {
      accessToken: accessToken,
      orderPayload: {
        BusinessCenter: input.businessCenter || config.businessCenterDefault || '10',
        Customer: g.customer,
        DeliveryPlace: g.deliveryPlace,
        CustomerOrderNumber: orderNum,
        CustomerOrderDate: orderDate,
        Text: input.emailSubject || 'Prednarudžba',
        Items: g.lines.map(line => ({
          ArticleID: String(line.articleId),
          ArticleDescCustomer: line.articleName || '',
          Quantity: parseFloat(line.quantity) || 0,
          DiscountPerc: parseFloat(line.discountPerc) || 0.0,
          Message: line.notes || ''
        }))
      },
      customerName: g.customerName,
      groupIndex: idx + 1,
      totalGroups: groupKeys.length,
      lineCount: g.lines.length,
      skippedLineCount: idx === 0 ? skippedLines.length : 0,
      skippedLines: idx === 0 ? skippedLines : []
    }
  };
});

// Process SaveTransferOrder response for current customer
const apiResponse = $input.first().json;

// Check if this is an error response (from onError: continueRegularOutput)
const isError = !!apiResponse.error || !!apiResponse.errorMessage;

if (isError) {
  return [{
    json: {
      submitted: false,
      error: apiResponse.error || apiResponse.errorMessage || 'Unknown API error',
      customerOrderNumber: apiResponse.CustomerOrderNumber || '',
      submittedAt: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    submitted: true,
    orderId: apiResponse.OrderID || null,
    status: apiResponse.Status || null,
    statusText: apiResponse.Status === 1 ? 'Received' : apiResponse.Status === 2 ? 'In process' : apiResponse.Status === 3 ? 'Processed' : 'Unknown',
    customerOrderNumber: apiResponse.CustomerOrderNumber || '',
    apiResponse: apiResponse,
    submittedAt: new Date().toISOString()
  }
}];

// Build single summary output from all customer order results
const results = $input.first().json.results || [];

const successes = results.filter(r => r.submitted);
const failures = results.filter(r => !r.submitted);

return [{
  json: {
    submitted: failures.length === 0 && successes.length > 0,
    totalGroups: results.length,
    successCount: successes.length,
    failedCount: failures.length,
    orders: successes.map(r => ({
      orderId: r.orderId,
      customerOrderNumber: r.customerOrderNumber,
      status: r.status,
      statusText: r.statusText
    })),
    errors: failures.map(r => ({
      customerOrderNumber: r.customerOrderNumber,
      error: r.error
    })),
    submittedAt: new Date().toISOString()
  }
}];

// DRY RUN: Preview the exact HTTP request that would be sent to the API
const input = $input.first().json;
const config = input.config || {};
const apiUrl = ($('Config').first().json.erpApiUrl || '') + '/api/SaveTransferOrder';

return [{
  json: {
    _mode: 'DRY_RUN',
    _note: 'This is a preview of the API request. No actual call was made.',
    request: {
      method: 'POST',
      url: apiUrl,
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + (input.accessToken ? input.accessToken.substring(0, 20) + '...' : '(no token)')
      },
      body: input.orderPayload
    },
    summary: {
      submittedLineCount: input.submittedLineCount,
      skippedLineCount: input.skippedLineCount,
      skippedLines: input.skippedLines,
      customerOrderNumber: input.orderPayload.CustomerOrderNumber,
      customer: input.orderPayload.Customer,
      deliveryPlace: input.orderPayload.DeliveryPlace,
      itemCount: (input.orderPayload.Items || []).length
    },
    submitted: true,
    orderId: 'DRY-RUN-' + Date.now(),
    submittedAt: new Date().toISOString()
  }
}];
